
export type TransformFunction = (value: number, row: any, rangeSeconds: number) => number;
export type Dimension = { text: string; value: string; field: string };

export type Metric = {
  value: string;
  column: string;
  fn: string;
  rank?: number;
  label: string;
  unit: string;
  group: string;
  origLabel: string;
  sample_rate: number;
  name: string;
  tableField?: {
    text: string;
    field: string;
    metric: string;
  };
};

type MetricGroup = {
  label: string;
  options: Metric[];
};

export function flattenMetricOptions(
  groups: MetricGroup[]
): Metric[] {
  return groups.flatMap(group => group.options);
}

export type FilterField = { text: string; field: string; unequatable?: boolean };

